export interface MappingRuleRecategorizePreviewInput {
  /** The category the user is considering moving the rule to. The
preview is computed against the rule's *current* `categoryId` as
the `fromCategoryId`; if the rule is currently uncategorized
(`categoryId: null`) or `toCategoryId` already matches it, the
response reports `candidateCount: 0`.
 */
  toCategoryId: string;
}

export type MappingRuleRecategorizePreviewMatchType =
  (typeof MappingRuleRecategorizePreviewMatchType)[keyof typeof MappingRuleRecategorizePreviewMatchType];

export const MappingRuleRecategorizePreviewMatchType = {
  contains: "contains",
  exact: "exact",
  starts_with: "starts_with",
} as const;

/**
 * Read-only preview of the bulk-recategorize that would happen if the
Mapping Rules edit UI saved a new `categoryId` for this rule and then
called POST /transactions/recategorize-by-pattern with the same
`{ pattern, matchType, fromCategoryId, toCategoryId }`. Mirrors the
`RepointedRule` shape so the same preview Dialog can render either.

 */
export interface MappingRuleRecategorizePreview {
  ruleId: string;
  pattern: string;
  matchType: MappingRuleRecategorizePreviewMatchType;
  /**
   * The rule's current `categoryId` at preview time. `null` when the
rule is currently uncategorized — in that case `candidateCount` is
always `0` because the bulk-recategorize endpoint requires a
concrete from-category to scope the update.

   * @nullable
   */
  fromCategoryId: string | null;
  toCategoryId: string;
  /** Number of transactions whose description matches the rule's
pattern AND that currently sit in `fromCategoryId`. `0` when the
target equals the from-category, when the rule is uncategorized,
or when no historical rows match.
 */
  candidateCount: number;
  /** First ~10 affected transactions, ordered most-recent first. Same
thin slice (id, description, occurredOn, amount) used by
`RepointedRule.sampleTransactions`.
 */
  sampleTransactions: RepointedRuleSample[];
}

export type MappingRulePatternRecategorizePreviewInputMatchType =
  (typeof MappingRulePatternRecategorizePreviewInputMatchType)[keyof typeof MappingRulePatternRecategorizePreviewInputMatchType];

export const MappingRulePatternRecategorizePreviewInputMatchType = {
  contains: "contains",
  exact: "exact",
  starts_with: "starts_with",
} as const;

/**
 * Pattern shape used by the "Add New Rule" form's inline preview.
Carries the unsaved rule directly so the server can compute
the candidate count + sample list against older *uncategorized*
rows without persisting anything.

`toCategoryId` is optional: the candidate count + samples only
depend on `pattern` + `matchType` (the bulk recategorize always
scopes to uncategorized rows), so the Add form can fire the
same request as soon as the user has typed a pattern — before
they pick a destination category — and avoid a refetch when
the category is then chosen.

 */
export interface MappingRulePatternRecategorizePreviewInput {
  /** The literal pattern the unsaved rule would match against
transaction descriptions.
 */
  pattern: string;
  matchType: MappingRulePatternRecategorizePreviewInputMatchType;
  /** Optional. The category the unsaved rule would assign
matching rows to. Echoed back in the response when supplied
so the client can confirm the preview lines up with the
currently-picked category, but doesn't affect the count.
 */
  toCategoryId?: string;
}

export type MappingRulePatternRecategorizePreviewMatchType =
  (typeof MappingRulePatternRecategorizePreviewMatchType)[keyof typeof MappingRulePatternRecategorizePreviewMatchType];

export const MappingRulePatternRecategorizePreviewMatchType = {
  contains: "contains",
  exact: "exact",
  starts_with: "starts_with",
} as const;

/**
 * Read-only preview of the bulk-recategorize that *would* happen if the
Mapping Rules "Add New Rule" form created a rule with the given
`{ pattern, matchType, toCategoryId }` and then chained
POST /transactions/recategorize-by-pattern against the older
uncategorized rows it would match. Mirrors `MappingRuleRecategorizePreview`
minus the `ruleId` (no rule exists yet) so the same preview banner +
"Show matches" Dialog can render either.

 */
export interface MappingRulePatternRecategorizePreview {
  pattern: string;
  matchType: MappingRulePatternRecategorizePreviewMatchType;
  /**
   * Always `null` for the by-pattern preview — the Add flow scopes
its bulk recategorize to uncategorized rows only, so explicit
user category edits aren't trampled. Surfaced as an explicit
field for symmetry with `MappingRuleRecategorizePreview`.

   * @nullable
   */
  fromCategoryId: string | null;
  /**
   * Echo of the request's `toCategoryId`. `null` when the caller
previewed before picking a destination category — the
candidate count + samples are still meaningful (they only
depend on pattern + matchType against uncategorized rows),
but the client should render a neutral "would match N
uncategorized past transactions" banner instead of the
"will move into <category>" copy.

   * @nullable
   */
  toCategoryId: string | null;
  /** Number of *uncategorized* transactions whose description matches
the unsaved rule's pattern. `0` when no historical rows match.
 */
  candidateCount: number;
  /** First ~10 affected transactions, ordered most-recent first. Same
thin slice (id, description, occurredOn, amount) used by
`RepointedRule.sampleTransactions`.
 */
  sampleTransactions: RepointedRuleSample[];
}

export interface TestMappingRulesResult {
  /** Every rule whose pattern matches the description, sorted by
priority descending — same order the categorize() hot path uses.
 */
  matches: TestMappingRulesMatch[];
  /**
   * The category that auto-categorize would assign, or null when no
matching rule has a category.

   * @nullable
   */
  winningCategoryId: string | null;
}

